code = """import json
# load purchases result from reviews (var_call_lZ7LbhSvDTBVTJ3oNTm0nu79)
purchases = var_call_lZ7LbhSvDTBVTJ3oNTm0nu79
# load books result from file path (var_call_ehJtOQqICSNxWQMf4YnN3x95)
books_file_path = var_call_ehJtOQqICSNxWQMf4YnN3x95
with open(books_file_path, 'r') as f:
    books = json.load(f)
# create mapping from purchase_id to rating and count
rating_map = {}
for p in purchases:
    try:
        rating_map[p['purchase_id']] = {
            'avg_rating': float(p['avg_rating']),
            'review_count': int(p['review_count'])
        }
    except:
        # skip malformed
        continue
# create set of expected book_ids by converting purchaseid_X -> bookid_X
expected_book_ids = set()
for pid in rating_map.keys():
    if pid.startswith('purchaseid_'):
        expected_book_ids.add('bookid_' + pid.split('purchaseid_')[-1])
    else:
        expected_book_ids.add(pid)
# filter books that are in expected_book_ids
matched = []
for b in books:
    bid = b.get('book_id')
    if bid in expected_book_ids:
        # reconstruct purchase id
        if bid.startswith('bookid_'):
            pid = 'purchaseid_' + bid.split('bookid_')[-1]
        else:
            pid = 'purchaseid_' + bid
        info = rating_map.get(pid, {})
        matched.append({
            'book_id': bid,
            'title': b.get('title'),
            'author': b.get('author'),
            'categories': b.get('categories'),
            'avg_rating': info.get('avg_rating'),
            'review_count': info.get('review_count'),
            'details': b.get('details')
        })
# Sort matched by avg_rating desc then review_count desc
matched.sort(key=lambda x: ((x['avg_rating'] if x['avg_rating'] is not None else 0), x['review_count'] if x['review_count'] is not None else 0), reverse=True)
# print result as JSON string
print("__RESULT__:")
print(json.dumps(matched))"""

